INSERT INTO `ag_quest_definitions` (`id`, `source_type`, `source_ref`, `name`, `description`, `reward`, `duration_value`, `duration_unit`, `min_level`, `preferred_classes_json`, `skill_requirements_json`, `personality_requirements_json`, `difficulty`, `status`, `quest_type`, `campaign_id`, `world_event_id`, `seasonal_event_id`, `experience_reward`, `skill_rewards_json`, `loot_table_json`, `procedural`, `sort_order`) VALUES
('goblin_camp', 'standard', NULL, 'Clear Goblin Camp', 'A goblin camp has been established near the village. Clear it out to protect the locals.', 150, 1800000, 'frontend_raw', 1, '["Warrior","Rogue"]', NULL, NULL, 'Easy', 'available', 'standard', NULL, NULL, NULL, 50, NULL, NULL, 0, 1),
('dragon_hunt', 'standard', NULL, 'Dragon Hunt', 'A dragon has been terrorizing the countryside. Hunt it down and claim the reward.', 500, 3600000, 'frontend_raw', 5, '["Warrior","Mage"]', NULL, NULL, 'Hard', 'available', 'standard', NULL, NULL, NULL, 200, NULL, NULL, 0, 2),
('bandit_ambush', 'standard', NULL, 'Bandit Ambush', 'Bandits have set up an ambush on the main trade route. Deal with them.', 300, 2400000, 'frontend_raw', 3, '["Rogue","Archer"]', NULL, NULL, 'Medium', 'available', 'standard', NULL, NULL, NULL, 120, NULL, NULL, 0, 3),
('treasure_hunt', 'standard', NULL, 'Lost Treasure', 'Locate and retrieve the lost treasure from the ancient ruins.', 400, 3000000, 'frontend_raw', 4, '["Mage","Rogue"]', NULL, NULL, 'Medium', 'available', 'standard', NULL, NULL, NULL, 160, NULL, NULL, 0, 4),
('dragon_01_scouts', 'campaign', 'dragon_threat', 'Dragon Cult Scouts', 'Reports have come in of strange hooded figures scouting the countryside. They bear the mark of an ancient dragon cult. Investigate their activities and gather intelligence.', 200, 2, 'frontend_raw', 2, '["Rogue","Archer"]', '{"stealth.sneaking":10}', NULL, 'Medium', 'available', 'campaign', 'dragon_threat', NULL, NULL, 50, '{"stealth.sneaking":5,"survival.tracking":3}', '[{"id":"cultist_cloak","name":"Cultist''s Cloak","type":"armor","rarity":"uncommon","stats":{"dexterity":8,"vitality":5},"crafted":false}]', 0, 5),
('dragon_02_ritual', 'campaign', 'dragon_threat', 'Disrupted Ritual', 'The cult is performing dark rituals to awaken an ancient dragon. Their ritual site has been located in the Whispering Woods. Stop them before it''s too late!', 400, 4, 'frontend_raw', 4, '["Mage","Warrior"]', '{"magic.spellPower":15,"combat.weaponMastery":15}', '{"courage":{"min":70}}', 'Hard', 'available', 'campaign', 'dragon_threat', NULL, NULL, 100, '{"magic.spellPower":8,"combat.weaponMastery":8}', '[{"id":"ritual_disrupting_blade","name":"Ritual Disrupting Blade","type":"weapon","rarity":"rare","stats":{"strength":15,"intelligence":10},"crafted":false}]', 0, 6),
('dragon_03_awakening', 'campaign', 'dragon_threat', 'The Dragon Awakens', 'Despite your efforts, the dragon has partially awakened. It rages across the land, destroying everything in its path. Only the bravest heroes can hope to stand against such a beast.', 1000, 7, 'frontend_raw', 8, '["Warrior","Mage"]', '{"combat.weaponMastery":25,"magic.spellPower":25,"combat.battleRage":20}', '{"courage":{"min":90},"teamwork":{"min":80}}', 'Epic', 'available', 'campaign', 'dragon_threat', NULL, NULL, 200, '{"combat.weaponMastery":15,"magic.spellPower":15,"combat.battleRage":10}', '[{"id":"dragonslayer_sword","name":"Dragonslayer''s Blade","type":"weapon","rarity":"legendary","stats":{"strength":35,"vitality":20,"intelligence":15},"crafted":false},{"id":"dragon_scale_armor","name":"Dragon Scale Armor","type":"armor","rarity":"legendary","stats":{"vitality":40,"strength":15},"crafted":false}]', 0, 7),
('kingdom_01_ruins', 'campaign', 'lost_kingdom', 'Ancient Ruins Discovery', 'Ancient ruins have been discovered that match descriptions of the lost Kingdom of Aethermoor. Initial exploration is needed to determine if this is indeed the legendary lost realm.', 150, 3, 'frontend_raw', 1, '["Archer","Rogue"]', '{"survival.tracking":8}', NULL, 'Easy', 'available', 'campaign', 'lost_kingdom', NULL, NULL, 40, '{"survival.tracking":5,"survival.herbalism":3}', '[{"id":"ancient_map","name":"Ancient Map Fragment","type":"accessory","rarity":"uncommon","stats":{"intelligence":5,"dexterity":5},"crafted":false}]', 0, 8),
('kingdom_02_guardians', 'campaign', 'lost_kingdom', 'Awakened Guardians', 'Your presence in the ruins has awakened ancient magical guardians. These constructs protect the kingdom''s secrets, but they must be overcome to proceed deeper.', 300, 4, 'frontend_raw', 3, '["Warrior","Mage"]', '{"combat.weaponMastery":12,"magic.spellPower":12}', NULL, 'Medium', 'available', 'campaign', 'lost_kingdom', NULL, NULL, 70, '{"combat.weaponMastery":6,"magic.spellPower":6}', '[{"id":"guardian_core","name":"Guardian''s Core","type":"accessory","rarity":"rare","stats":{"intelligence":12,"vitality":8},"crafted":false}]', 0, 9),
('kingdom_03_treasury', 'campaign', 'lost_kingdom', 'The Royal Treasury', 'You''ve reached the heart of Aethermoor - the royal treasury. But it''s guarded by the kingdom''s most powerful defenses and the spirit of its last king.', 800, 6, 'frontend_raw', 6, '["Mage","Warrior"]', '{"magic.spellPower":20,"combat.tacticalKnowledge":15,"magic.elementalMastery":18}', '{"ambition":{"min":60},"courage":{"min":75}}', 'Hard', 'available', 'campaign', 'lost_kingdom', NULL, NULL, 150, '{"magic.spellPower":12,"combat.tacticalKnowledge":10,"magic.elementalMastery":8}', '[{"id":"crown_of_aethermoor","name":"Crown of Aethermoor","type":"accessory","rarity":"legendary","stats":{"intelligence":30,"strength":10,"dexterity":10,"vitality":10},"crafted":false}]', 0, 10),
('thieves_01_infiltration', 'campaign', 'thieves_guild', 'Guild Infiltration', 'A rival thieves'' guild has been stealing contracts from legitimate adventurer guilds. Infiltrate their organization to gather evidence of their crimes.', 180, 2, 'frontend_raw', 2, '["Rogue"]', '{"stealth.sneaking":15,"stealth.lockpicking":10}', '{"greed":{"max":60}}', 'Medium', 'available', 'campaign', 'thieves_guild', NULL, NULL, 45, '{"stealth.sneaking":8,"stealth.lockpicking":5}', '[{"id":"thieves_tools","name":"Master Thief''s Tools","type":"accessory","rarity":"uncommon","stats":{"dexterity":10,"intelligence":5},"crafted":false}]', 0, 11),
('thieves_02_heist', 'campaign', 'thieves_guild', 'The Grand Heist', 'The thieves'' guild is planning to steal a powerful artifact from the city''s temple. Stop their heist and recover the artifact before it falls into the wrong hands.', 350, 5, 'frontend_raw', 5, '["Rogue","Warrior"]', '{"stealth.sneaking":18,"combat.tacticalKnowledge":15,"stealth.lockpicking":12}', NULL, 'Hard', 'available', 'campaign', 'thieves_guild', NULL, NULL, 85, '{"stealth.sneaking":10,"combat.tacticalKnowledge":8}', '[{"id":"shadow_cloak","name":"Cloak of Shadows","type":"armor","rarity":"rare","stats":{"dexterity":18,"intelligence":8},"crafted":false}]', 0, 12),
('thieves_03_showdown', 'campaign', 'thieves_guild', 'Guild Master Showdown', 'Track down the guild master of the thieves'' organization. This master thief has eluded justice for years, but with the evidence you''ve gathered, it''s time for a final confrontation.', 600, 4, 'frontend_raw', 7, '["Rogue","Archer"]', '{"stealth.assassination":20,"stealth.sneaking":25,"combat.tacticalKnowledge":18}', '{"loyalty":{"min":80},"courage":{"min":70}}', 'Epic', 'available', 'campaign', 'thieves_guild', NULL, NULL, 120, '{"stealth.assassination":12,"stealth.sneaking":10,"combat.tacticalKnowledge":8}', '[{"id":"master_thieves_blade","name":"Master Thief''s Blade","type":"weapon","rarity":"epic","stats":{"dexterity":25,"strength":15,"intelligence":10},"crafted":false}]', 0, 13),
('festival_guard_duty', 'world_event', 'merchant_festival', 'Festival Security', 'The merchant festival needs security to prevent theft and maintain order among the crowds.', 150, 1, 'frontend_raw', 1, '["Warrior","Archer"]', NULL, NULL, 'Easy', 'available', 'world_event', NULL, 'merchant_festival', NULL, 30, '{"combat.tacticalKnowledge":3}', NULL, 0, 14),
('merchant_escort', 'world_event', 'merchant_festival', 'VIP Merchant Escort', 'A wealthy merchant needs protection while transporting valuable goods to the festival.', 300, 3, 'frontend_raw', 3, '["Warrior","Rogue"]', NULL, NULL, 'Medium', 'available', 'world_event', NULL, 'merchant_festival', NULL, 60, '{"combat.weaponMastery":5,"survival.tracking":3}', NULL, 0, 15),
('magical_anomaly', 'world_event', 'arcane_surge', 'Magical Anomaly Investigation', 'Strange magical phenomena are occurring throughout the city. Investigate and contain these anomalies.', 250, 2, 'frontend_raw', 3, '["Mage"]', '{"magic.spellPower":15}', NULL, 'Medium', 'available', 'world_event', NULL, 'arcane_surge', NULL, 50, '{"magic.spellPower":8,"magic.elementalMastery":5}', NULL, 0, 16),
('unstable_portal', 'world_event', 'arcane_surge', 'Unstable Portal Closure', 'An unstable magical portal has opened in the town square. Close it before something dangerous comes through.', 500, 4, 'frontend_raw', 5, '["Mage"]', '{"magic.spellPower":20,"magic.elementalMastery":15}', NULL, 'Hard', 'available', 'world_event', NULL, 'arcane_surge', NULL, 100, '{"magic.spellPower":12,"magic.elementalMastery":10}', NULL, 0, 17),
('goblin_raid_defense', 'world_event', 'goblin_uprising', 'Village Defense', 'A village is under attack by organized goblin raiders. Defend the innocent and drive off the attackers.', 400, 2, 'frontend_raw', 4, '["Warrior","Archer"]', NULL, '{"courage":{"min":60}}', 'Hard', 'available', 'world_event', NULL, 'goblin_uprising', NULL, 80, '{"combat.weaponMastery":8,"combat.battleRage":6}', NULL, 0, 18),
('warlord_hunt', 'world_event', 'goblin_uprising', 'Hunt the Goblin Warlord', 'Track down and eliminate the goblin warlord who has united the tribes. End this uprising at its source.', 800, 7, 'frontend_raw', 7, '["Warrior","Archer","Rogue"]', '{"combat.weaponMastery":20,"survival.tracking":15}', '{"courage":{"min":80},"teamwork":{"min":70}}', 'Epic', 'available', 'world_event', NULL, 'goblin_uprising', NULL, 160, '{"combat.weaponMastery":15,"combat.battleRage":12,"survival.tracking":10}', NULL, 0, 19),
('rift_sealing', 'world_event', 'planar_rift', 'Planar Rift Sealing', 'Use powerful magic to seal tears in reality before more dangerous creatures emerge.', 1000, 6, 'frontend_raw', 8, '["Mage"]', '{"magic.spellPower":25,"magic.elementalMastery":20,"magic.manaEfficiency":15}', '{"courage":{"min":85}}', 'Epic', 'available', 'world_event', NULL, 'planar_rift', NULL, 200, '{"magic.spellPower":20,"magic.elementalMastery":15,"magic.manaEfficiency":10}', NULL, 0, 20),
('planar_creature_hunt', 'world_event', 'planar_rift', 'Otherworldly Beast Hunt', 'Hunt down the dangerous creatures that have escaped through the planar rifts before they can establish territory.', 600, 5, 'frontend_raw', 6, '["Warrior","Archer"]', '{"combat.weaponMastery":18,"survival.tracking":12}', NULL, 'Hard', 'available', 'world_event', NULL, 'planar_rift', NULL, 120, '{"combat.weaponMastery":10,"survival.tracking":8,"combat.battleRage":6}', NULL, 0, 21),
('awaken_grove', 'seasonal', 'spring_awakening', 'Awaken the Sacred Grove', 'Help the forest spirits perform the ritual of spring awakening in the ancient sacred grove.', 300, 4, 'frontend_raw', 3, '["Mage","Archer"]', '{"magic.elementalMastery":12,"survival.herbalism":10}', '{"ambition":{"min":40}}', 'Medium', 'available', 'seasonal', NULL, NULL, 'spring_awakening', 80, '{"magic.elementalMastery":10,"survival.herbalism":8}', NULL, 0, 22),
('flower_festival', 'seasonal', 'spring_awakening', 'Flower Festival Guardian', 'Protect the flower festival from creatures corrupted by winter''s lingering darkness.', 200, 2, 'frontend_raw', 2, '["Warrior","Rogue"]', NULL, NULL, 'Easy', 'available', 'seasonal', NULL, NULL, 'spring_awakening', 50, '{"combat.weaponMastery":6}', NULL, 0, 23),
('trials_of_flame', 'seasonal', 'summer_solstice', 'Trials of the Eternal Flame', 'Prove your worth by completing the ancient fire trials that test courage, strength, and wisdom.', 500, 6, 'frontend_raw', 5, '["Warrior","Mage"]', '{"combat.battleRage":15,"magic.elementalMastery":18}', '{"courage":{"min":75}}', 'Hard', 'available', 'seasonal', NULL, NULL, 'summer_solstice', 120, '{"combat.battleRage":12,"magic.elementalMastery":10}', NULL, 0, 24),
('fire_elemental_pact', 'seasonal', 'summer_solstice', 'Forge a Fire Elemental Pact', 'Negotiate with powerful fire elementals to secure their blessing for your guild.', 400, 3, 'frontend_raw', 6, '["Mage"]', '{"magic.elementalMastery":20,"magic.spellPower":22}', '{"ambition":{"min":70}}', 'Hard', 'available', 'seasonal', NULL, NULL, 'summer_solstice', 100, '{"magic.elementalMastery":15,"magic.spellPower":12}', NULL, 0, 25),
('protect_harvest', 'seasonal', 'harvest_moon', 'Protect the Great Harvest', 'Guard the village harvest from ravenous creatures drawn by the abundance of food.', 350, 5, 'frontend_raw', 4, '["Warrior","Archer"]', '{"combat.weaponMastery":16,"survival.tracking":12}', NULL, 'Medium', 'available', 'seasonal', NULL, NULL, 'harvest_moon', 85, '{"combat.weaponMastery":8,"survival.tracking":6}', NULL, 0, 26),
('moon_ritual', 'seasonal', 'harvest_moon', 'Harvest Moon Blessing Ritual', 'Participate in the sacred ritual to bless the harvest and ensure prosperity for the coming winter.', 250, 3, 'frontend_raw', 3, '["Mage"]', '{"magic.elementalMastery":14}', '{"teamwork":{"min":60}}', 'Medium', 'available', 'seasonal', NULL, NULL, 'harvest_moon', 65, '{"magic.elementalMastery":8,"magic.manaEfficiency":6}', NULL, 0, 27),
('ice_palace', 'seasonal', 'winter_solstice', 'Explore the Ice Palace', 'Venture into the mystical ice palace that appears only on the longest night.', 600, 8, 'frontend_raw', 7, '["Mage","Warrior"]', '{"magic.elementalMastery":25,"combat.tacticalKnowledge":20}', '{"courage":{"min":80},"ambition":{"min":65}}', 'Epic', 'available', 'seasonal', NULL, NULL, 'winter_solstice', 150, '{"magic.elementalMastery":18,"combat.tacticalKnowledge":15}', NULL, 0, 28),
('winter_spirit', 'seasonal', 'winter_solstice', 'Commune with Winter Spirits', 'Seek wisdom from the ancient spirits of winter who remember the world''s earliest days.', 400, 4, 'frontend_raw', 5, '["Mage"]', '{"magic.spellPower":18,"magic.manaEfficiency":15}', '{"loyalty":{"min":70}}', 'Hard', 'available', 'seasonal', NULL, NULL, 'winter_solstice', 95, '{"magic.spellPower":12,"magic.manaEfficiency":10}', NULL, 0, 29),
('dragon_trial', 'seasonal', 'dragons_return', 'Trial of the Ancient Dragon', 'Face the ultimate test as an ancient dragon evaluates your guild''s worthiness.', 1000, 10, 'frontend_raw', 10, '["Warrior","Mage"]', '{"combat.weaponMastery":30,"magic.spellPower":30,"combat.battleRage":25,"magic.elementalMastery":25}', '{"courage":{"min":90},"loyalty":{"min":85},"teamwork":{"min":80}}', 'Epic', 'available', 'seasonal', NULL, NULL, 'dragons_return', 250, '{"combat.weaponMastery":20,"magic.spellPower":20,"combat.battleRage":15,"magic.elementalMastery":15}', NULL, 0, 30);
INSERT INTO `ag_campaign_definitions` (`id`, `name`, `description`, `quest_ids_json`, `rewards_json`, `sort_order`) VALUES
('dragon_threat', 'The Dragon Threat', 'An ancient dragon cult seeks to awaken a terrible beast that has slumbered for centuries. Can your guild stop them before it''s too late?', '["dragon_01_scouts","dragon_02_ritual","dragon_03_awakening"]', '{"gold":2000,"reputation":300,"items":[{"id":"dragon_slayer_title","name":"Dragon Slayer''s Mantle","type":"armor","rarity":"legendary","stats":{"strength":25,"vitality":25,"intelligence":15,"dexterity":15},"crafted":false}]}', 1),
('lost_kingdom', 'The Lost Kingdom of Aethermoor', 'Legends speak of a kingdom that vanished overnight, leaving behind only ruins and treasures. Explore its mysteries and uncover its fate.', '["kingdom_01_ruins","kingdom_02_guardians","kingdom_03_treasury"]', '{"gold":1500,"reputation":200,"items":[{"id":"aethermoor_blessing","name":"Blessing of Aethermoor","type":"accessory","rarity":"legendary","stats":{"intelligence":20,"strength":20,"dexterity":20,"vitality":20},"crafted":false}]}', 2),
('thieves_guild', 'War of the Guilds', 'A corrupt thieves'' guild threatens the reputation of all adventurer organizations. Infiltrate their ranks and bring them to justice.', '["thieves_01_infiltration","thieves_02_heist","thieves_03_showdown"]', '{"gold":1200,"reputation":250,"items":[{"id":"guild_protector_badge","name":"Guild Protector''s Badge","type":"accessory","rarity":"epic","stats":{"intelligence":15,"dexterity":15,"vitality":10},"crafted":false}]}', 3);
