INSERT INTO `ag_world_event_definitions` (`id`, `name`, `description`, `active_default`, `duration_days`, `quest_reward_multiplier`, `adventurer_morale_bonus`, `effects_json`, `sort_order`) VALUES
('merchant_festival', 'Grand Merchant Festival', 'Traders from across the realm have gathered for the annual merchant festival. Gold flows freely and opportunities abound.', 0, 7, 1.5, 20, '{"questRewardMultiplier":1.5,"adventurerMoraleBonus":20,"specialQuestsAvailable":["festival_guard_duty","merchant_escort","festival_entertainment"]}', 1),
('arcane_surge', 'Arcane Surge', 'Magical energies surge throughout the land, empowering spellcasters but creating dangerous magical anomalies.', 0, 5, 1.3, NULL, '{"questRewardMultiplier":1.3,"specialQuestsAvailable":["magical_anomaly","arcane_research","unstable_portal"]}', 2),
('goblin_uprising', 'Goblin Uprising', 'Goblin tribes across the region have united under a powerful warlord, launching coordinated attacks on settlements.', 0, 10, 1.8, -10, '{"questRewardMultiplier":1.8,"adventurerMoraleBonus":-10,"specialQuestsAvailable":["goblin_raid_defense","warlord_hunt","supply_line_disruption"]}', 3),
('harvest_moon', 'Harvest Moon Blessing', 'The harvest moon brings prosperity to the land. Crops grow bountifully and spirits are high.', 0, 3, 1.2, 15, '{"questRewardMultiplier":1.2,"adventurerMoraleBonus":15,"specialQuestsAvailable":["harvest_protection","moon_ritual","abundant_gathering"]}', 4),
('planar_rift', 'Planar Rift Crisis', 'A tear in reality has opened, allowing creatures from other planes to pour through. The very fabric of existence is at stake.', 0, 14, 2.5, -20, '{"questRewardMultiplier":2.5,"adventurerMoraleBonus":-20,"specialQuestsAvailable":["rift_sealing","planar_creature_hunt","reality_anchor"]}', 5),
('dragon_migration', 'Dragon Migration', 'Ancient dragons are migrating across the skies, their presence both terrifying and awe-inspiring.', 0, 6, 2.0, NULL, '{"questRewardMultiplier":2,"specialQuestsAvailable":["dragon_sighting","scale_collection","dragon_negotiation"]}', 6),
('bards_convention', 'Grand Bards'' Convention', 'Storytellers and musicians gather to share tales and songs, inspiring all who hear them.', 0, 4, 1.1, 25, '{"questRewardMultiplier":1.1,"adventurerMoraleBonus":25,"specialQuestsAvailable":["tale_collection","musical_quest","inspiration_spreading"]}', 7),
('undead_plague', 'Undead Plague', 'Dark necromancy has raised the dead across multiple graveyards. The living must band together against this threat.', 0, 12, 2.2, -15, '{"questRewardMultiplier":2.2,"adventurerMoraleBonus":-15,"specialQuestsAvailable":["graveyard_cleansing","necromancer_hunt","holy_blessing"]}', 8);
