INSERT INTO `ag_faction_definitions` (`id`, `name`, `base_reputation`, `description`, `reward_multiplier`, `quest_modifiers_json`, `sort_order`) VALUES
('merchants_guild', 'Merchants'' Guild', 0, 'A powerful organization of traders and merchants who control much of the region''s commerce.', 1.2, '{"rewardMultiplier":1.2,"availableQuestTypes":["merchant_escort","trade_route_security","cargo_protection"]}', 1),
('temple_of_light', 'Temple of Light', 0, 'A religious organization dedicated to fighting darkness and evil throughout the land.', 1.1, '{"rewardMultiplier":1.1,"availableQuestTypes":["undead_cleansing","holy_blessing","temple_protection","divine_quest"]}', 2),
('royal_guard', 'Royal Guard', 0, 'The elite military force serving the crown, often requesting assistance with matters of national security.', 1.3, '{"rewardMultiplier":1.3,"availableQuestTypes":["royal_escort","border_patrol","investigation","diplomatic_mission"]}', 3),
('mages_circle', 'Circle of Mages', 0, 'An ancient order of wizards and scholars dedicated to the study and preservation of magical knowledge.', 1.25, '{"rewardMultiplier":1.25,"availableQuestTypes":["magical_research","artifact_recovery","spell_component_gathering","arcane_study"]}', 4),
('thieves_brotherhood', 'Thieves'' Brotherhood', 0, 'A secretive organization of rogues and information brokers who operate in the shadows.', 1.4, '{"rewardMultiplier":1.4,"availableQuestTypes":["stealth_mission","information_gathering","infiltration","heist_planning"]}', 5),
('forest_druids', 'Forest Druids', 0, 'Guardians of nature who seek to maintain the balance between civilization and the wild.', 1.15, '{"rewardMultiplier":1.15,"availableQuestTypes":["forest_protection","beast_taming","nature_restoration","druid_ritual"]}', 6),
('artisan_league', 'Artisan League', 0, 'A confederation of skilled craftspeople who create the finest weapons, armor, and tools.', 1.1, '{"rewardMultiplier":1.1,"availableQuestTypes":["material_gathering","workshop_protection","delivery_mission","quality_inspection"]}', 7),
('mountain_clans', 'Mountain Clans', 0, 'Hardy folk who dwell in the high peaks and valleys, known for their mining expertise and warrior traditions.', 1.2, '{"rewardMultiplier":1.2,"availableQuestTypes":["mining_expedition","mountain_patrol","clan_dispute","monster_hunt"]}', 8);
