INSERT INTO `ag_seasonal_event_definitions` (`id`, `name`, `description`, `season`, `duration_days`, `rewards_json`, `special_recruits_json`, `unlock_conditions_json`, `sort_order`) VALUES
('spring_awakening', 'Spring Awakening Festival', 'Nature blooms anew and magical energies flow freely. Ancient spirits awaken from winter slumber.', 'spring', 10, '{"goldBonus":1.2,"experienceBonus":1.3,"specialItems":[{"id":"bloom_staff","name":"Staff of Eternal Bloom","type":"weapon","rarity":"epic","stats":{"intelligence":25,"vitality":15,"dexterity":10},"crafted":false},{"id":"nature_crown","name":"Crown of Nature''s Favor","type":"accessory","rarity":"rare","stats":{"intelligence":18,"vitality":12},"crafted":false}]}', '[{"id":"spring_druid","name":"Grove Keeper Elara","level":4,"class":"Mage","cost":400,"personality":{"courage":60,"loyalty":85,"ambition":45,"teamwork":80,"greed":20},"potentialSkills":{"magic.elementalMastery":20,"survival.herbalism":18,"magic.spellPower":15}}]', NULL, 1),
('summer_solstice', 'Midsummer Fire Festival', 'The sun reaches its peak power, and fire elementals dance in celebration. Heroes test their courage against trials of flame.', 'summer', 7, '{"goldBonus":1.5,"experienceBonus":1.2,"specialItems":[{"id":"solar_blade","name":"Sword of Solar Flare","type":"weapon","rarity":"legendary","stats":{"strength":30,"intelligence":15,"vitality":20},"crafted":false},{"id":"flame_cloak","name":"Cloak of Dancing Flames","type":"armor","rarity":"epic","stats":{"vitality":20,"intelligence":18,"dexterity":12},"crafted":false}]}', NULL, '{"guildLevel":3,"reputation":150}', 2),
('harvest_moon', 'Harvest Moon Celebration', 'The autumn harvest brings abundance, but also awakens creatures that feed on the bounty.', 'autumn', 8, '{"goldBonus":1.8,"experienceBonus":1.1,"specialItems":[{"id":"harvest_scythe","name":"Moonlit Harvest Scythe","type":"weapon","rarity":"epic","stats":{"strength":22,"dexterity":18,"vitality":15},"crafted":false},{"id":"bounty_pouch","name":"Endless Bounty Pouch","type":"accessory","rarity":"rare","stats":{"vitality":15,"intelligence":12,"strength":8},"crafted":false}]}', NULL, NULL, 3),
